if (! function_exists('hex_dump')) {
    function hex_dump($path, $bytes = null, $offset = null, $width = null, $ascii = null, $html = null)
    {
        $path = isset($path) ? (string)$path : '';
        $bytes = isset($bytes) ? max(16, min(65536, (int)$bytes)) : 256;
        $offset = isset($offset) ? max(0, (int)$offset) : 0;
        $width = isset($width) ? (int)$width : 16;
        $show_ascii = $ascii ?? true;
