        if (empty($path)) return ['error' => 'path is required.', 'success' => false];
        $valid_widths = [8, 16, 32, 64];
        if (!in_array($width, $valid_widths)) $width = 16;

        $project_root = realpath(__DIR__ . '/../../..');
        if (!$project_root) return ['error' => 'Could not determine project root.', 'success' => false];
        $resolved = realpath($path);
        if (!$resolved) {
            $try = $project_root . '/' . ltrim($path, '/\\');
