        $actual = strlen($data);
        $lines = [];

        // Magic byte detection from actual file header (not offset)
        $fp2 = @fopen($resolved, 'rb');
        $hdr = $fp2 ? fread($fp2, 16) : $data;
        if ($fp2) fclose($fp2);
        $hex_h = strtolower(bin2hex($hdr));

        $magic_db = [
            '89504e47' => 'PNG image', '47494638' => 'GIF image',
            'ffd8ffe0' => 'JPEG image', 'ffd8ffe1' => 'JPEG EXIF',
